  1→import { type KeyboardEvent, Fragment, useEffect, useRef } from 'react';
  2→import type { BreadcrumbItem } from '../../hooks/use_navigation';
  3→import './search_bar.scss';
  4→
  5→interface SearchBarProps {
  6→  value: string;
  7→  onChange: (value: string) => void;
  8→  placeholder?: string;
  9→  activeDescendantId?: string;
 10→  breadcrumbs?: BreadcrumbItem[];
 11→}
 12→
 13→export function SearchBar({
 14→  value,
 15→  onChange,
 16→  placeholder = 'Search...',
 17→  activeDescendantId,
 18→  breadcrumbs,
 19→}: SearchBarProps) {
 20→  const inputRef = useRef<HTMLInputElement>(null);
 21→
 22→  useEffect(() => {
 23→    inputRef.current?.focus();
 24→  }, []);
 25→
 26→  function handleInputKeyDown(e: KeyboardEvent<HTMLInputElement>) {
 27→    if (e.key !== 'Escape' || !breadcrumbs || breadcrumbs.length === 0) {
 28→      return;
 29→    }
 30→
 31→    e.preventDefault();
 32→    if (value) {
 33→      onChange('');
 34→      return;
 35→    }
 36→
 37→    for (let i = breadcrumbs.length - 1; i >= 0; i--) {
 38→      const crumb = breadcrumbs[i];
 39→      if (crumb?.onBack) {
 40→        crumb.onBack();
 41→        return;
 42→      }
 43→    }
 44→  }
 45→
 46→  return (
 47→    <div className="search-bar" role="search">
 48→      <svg
 49→        className="search-bar__icon"
 50→        width="20"
 51→        height="20"
 52→        viewBox="0 0 20 20"
 53→        fill="none"
 54→        xmlns="http://www.w3.org/2000/svg"
 55→      >
 56→        <circle cx="9" cy="9" r="5.5" stroke="currentColor" strokeWidth="1.5" />
 57→        <line
 58→          x1="13.25"
 59→          y1="13.25"
 60→          x2="17.5"
 61→          y2="17.5"
 62→          stroke="currentColor"
 63→          strokeWidth="1.5"
 64→          strokeLinecap="round"
 65→        />
 66→      </svg>
 67→      {breadcrumbs && breadcrumbs.length > 0 && (
 68→        <nav className="search-bar__breadcrumbs" aria-label="Breadcrumb">
 69→          {breadcrumbs.map((crumb, i) => {
 70→            const isLast = i === breadcrumbs.length - 1;
 71→            return (
 72→              <Fragment key={i}>
 73→                {i > 0 && (
 74→                  <svg
 75→                    className="search-bar__breadcrumb-chevron"
 76→                    width="8"
 77→                    height="8"
 78→                    viewBox="0 0 8 8"
 79→                    fill="none"
 80→                    aria-hidden="true"
 81→                  >
 82→                    <path
 83→                      d="M2.5 1.5L5.5 4L2.5 6.5"
 84→                      stroke="currentColor"
 85→                      strokeWidth="1.2"
 86→                      strokeLinecap="round"
 87→                      strokeLinejoin="round"
 88→                    />
 89→                  </svg>
 90→                )}
 91→                {isLast ? (
 92→                  <span
 93→                    className="search-bar__breadcrumb search-bar__breadcrumb--current"
 94→                    aria-current="location"
 95→                  >
 96→                    {crumb.label}
 97→                  </span>
 98→                ) : (
 99→                  <button
100→                    className="search-bar__breadcrumb"
101→                    onClick={crumb.onBack}
102→                    type="button"
103→                    aria-label={`Back to ${crumb.label}`}
104→                  >
105→                    {crumb.label}
106→                  </button>
107→                )}
108→              </Fragment>
109→            );
110→          })}
111→        </nav>
112→      )}
113→      <input
114→        ref={inputRef}
115→        className="search-bar__input"
116→        type="text"
117→        value={value}
118→        onChange={e => onChange(e.target.value)}
119→        onKeyDown={handleInputKeyDown}
120→        placeholder={placeholder}
121→        role="combobox"
122→        aria-expanded={true}
123→        aria-controls="command-list"
124→        aria-activedescendant={activeDescendantId}
125→        aria-label="Search commands"
126→        spellCheck={false}
127→        autoComplete="off"
128→      />
129→    </div>
130→  );
131→}
